+      .exec("SELECT path FROM files WHERE is_dir = 0")
+      .toArray();
+    for (const row of indexed) {
+      const path = row.path as string;
+      if (!r2Paths.has(path)) {
+        this.sql.exec("DELETE FROM files WHERE path = ?", path);
+        this.sql.exec("DELETE FROM file_cache WHERE path = ?", path);
+      }
+    }
+  }
